Deno.serve(async (req) => {
  if (req.method !== "POST") return Response.json({ error: "Method not allowed" }, { status: 405 });
  const base44 = createClientFromRequest(req);
  const user = await base44.auth.me();
  if (user?.role !== "admin") return Response.json({ error: "Forbidden: Admin access required" }, { status: 403 });

  const { force } = await req.json().catch(() => ({}));

  // Check if library already seeded
  const existing = await base44.asServiceRole.entities.GameLibrary.list("-sort_priority", 5);
  if (existing.length > 0 && !force) {
    return Response.json({ message: "Library already seeded", count: existing.length });
  }

  const created = [];
  for (const game of SEED_GAMES) {
    const record = await base44.asServiceRole.entities.GameLibrary.create({
      ...game,
      normalized_title: game.title.toLowerCase(),
      pc_supported: true,
      is_active: true,
    });
    created.push(record.id);
  }

  return Response.json({ message: `Seeded ${created.length} games`, ids: created });
});